+    pub fn deinit(self: *Self) void {
+        // Release cached weights if any
+        if (self.cached_router) |buf| objc.release(buf);
+        for (0..8) |i| {
+            if (self.cached_expert_gate[i]) |buf| objc.release(buf);
+            if (self.cached_expert_up[i]) |buf| objc.release(buf);
+            if (self.cached_expert_down[i]) |buf| objc.release(buf);
+        }
+
+        objc.release(self.buf_output);
+        objc.release(self.buf_intermediate);
+        objc.release(self.buf_expert_weights);
+        objc.release(self.buf_expert_ids);
+        objc.release(self.buf_router_logits);
+        objc.release(self.buf_hidden_states);
+        objc.release(self.command_queue);
+        objc.release(self.device);
+        self.allocator.destroy(self);
+    }
