+    /// Upload Q8_0 quantized weights to GPU buffer
+    pub fn uploadQ8ToGPU(self: *Self, q8_data: []const u8) !objc.MTLBuffer {
+        const buffer = objc.deviceNewBuffer(self.device, q8_data.len, objc.MTLResourceStorageModeShared) orelse {
+            return error.MetalBufferAllocationFailed;
+        };
+
+        const buffer_ptr: [*]u8 = @ptrCast(@alignCast(objc.bufferContents(buffer)));
+        @memcpy(buffer_ptr[0..q8_data.len], q8_data);
+
+        return buffer;
+    }
