+    /// Complete MoE FFN forward pass on GPU with Q8_0 weights
+    /// This is the key function - operates directly on quantized weights
+    pub fn moeFFN_Q8(
+        self: *Self,
+        allocator: std.mem.Allocator,
+        x: []const f32,                              // [n_embd]
+        router_weights_q8: []const u8,               // Q8_0 quantized
+        expert_gate_weights_q8: [8][]const u8,       // Q8_0 quantized per expert
+        expert_up_weights_q8: [8][]const u8,         // Q8_0 quantized per expert
+        expert_down_weights_q8: [8][]const u8,       // Q8_0 quantized per expert
+        n_expert: u32,
+        n_embd: u32,
+        n_ff: u32,
+    ) ![]f32 {
+        std.debug.assert(n_expert == 8);
+        std.debug.assert(n_embd == 4096);
+        std.debug.assert(n_ff == 14336);
+
+        // Cache weights on first call (upload once, reuse forever)
+        if (!self.weights_cached) {
+            log.info("Uploading Q8_0 weights to GPU (one-time cost ~500MB)...", .{});
+            self.cached_router = try self.uploadQ8ToGPU(router_weights_q8);
+
+            for (0..8) |i| {
+                self.cached_expert_gate[i] = try self.uploadQ8ToGPU(expert_gate_weights_q8[i]);
+                self.cached_expert_up[i] = try self.uploadQ8ToGPU(expert_up_weights_q8[i]);
+                self.cached_expert_down[i] = try self.uploadQ8ToGPU(expert_down_weights_q8[i]);
+            }
+
+            self.weights_cached = true;
+            log.info("Weights cached on GPU successfully", .{});
+        }
+
+        const router_gpu = self.cached_router.?;
+        var expert_gate_gpu: [8]objc.MTLBuffer = undefined;
+        var expert_up_gpu: [8]objc.MTLBuffer = undefined;
+        var expert_down_gpu: [8]objc.MTLBuffer = undefined;
+
+        for (0..8) |i| {
+            expert_gate_gpu[i] = self.cached_expert_gate[i].?;
+            expert_up_gpu[i] = self.cached_expert_up[i].?;
+            expert_down_gpu[i] = self.cached_expert_down[i].?;
+        }
+
+        // Copy input to GPU
+        const hidden_states_ptr: [*]f32 = @ptrCast(@alignCast(objc.bufferContents(self.buf_hidden_states)));
+        @memcpy(hidden_states_ptr[0..n_embd], x);
+
+        // Create command buffer
+        const cmd_buffer = objc.commandQueueCommandBuffer(self.command_queue) orelse {
+            return error.MetalCommandBufferCreationFailed;
+        };
+        defer objc.release(cmd_buffer);
+
+        // Step 1: Router (compute logits + top-K selection)
+        try self.routerTopK_Q8(cmd_buffer, router_gpu, n_expert, n_embd);
+
+        // Commit and wait for router results
+        objc.commandBufferCommit(cmd_buffer);
+        objc.commandBufferWaitUntilCompleted(cmd_buffer);
+
+        // Read back expert IDs
+        const expert_ids_ptr: [*]u32 = @ptrCast(@alignCast(objc.bufferContents(self.buf_expert_ids)));
+        const expert_weights_ptr: [*]f32 = @ptrCast(@alignCast(objc.bufferContents(self.buf_expert_weights)));
+        const selected_experts = [2]u32{ expert_ids_ptr[0], expert_ids_ptr[1] };
+        const selected_weights = [2]f32{ expert_weights_ptr[0], expert_weights_ptr[1] };
+
+        // Create new command buffer for expert computation
+        const cmd_buffer2 = objc.commandQueueCommandBuffer(self.command_queue) orelse {
+            return error.MetalCommandBufferCreationFailed;
+        };
+        defer objc.release(cmd_buffer2);
+
+        // Step 2: Zero output buffer
+        try self.zeroBuffer(cmd_buffer2, self.buf_output, n_embd);
+
+        // Step 3: Compute selected expert outputs with Q8_0 kernels
+        for (0..2) |k| {
+            const expert_idx = selected_experts[k];
+            const weight = selected_weights[k];
+
+            // Run fused Q8_0 expert FFN
+            try self.expertFFN_Q8(
+                cmd_buffer2,
+                self.buf_hidden_states,
+                expert_gate_gpu[expert_idx],
+                expert_up_gpu[expert_idx],
+                expert_down_gpu[expert_idx],
+                self.buf_intermediate,
+                n_embd,
+                n_ff,
+            );
+
+            // Weighted add
+            try self.weightedAdd(cmd_buffer2, self.buf_output, self.buf_intermediate, weight, n_embd);
+        }
+
+        // Commit and wait
+        objc.commandBufferCommit(cmd_buffer2);
+        objc.commandBufferWaitUntilCompleted(cmd_buffer2);
+
+        // Copy result back to CPU
+        const result = try allocator.alloc(f32, n_embd);
+        const output_ptr: [*]f32 = @ptrCast(@alignCast(objc.bufferContents(self.buf_output)));
+        @memcpy(result, output_ptr[0..n_embd]);
+
+        return result;
+    }
+
