+    /// Complete MoE FFN forward pass on GPU with F32 weights (legacy)
+    /// This is the main entry point - replaces moeFFN_simd with GPU version
+    pub fn moeFFN(
+        self: *Self,
+        allocator: std.mem.Allocator,
+        x: []const f32,                      // [n_embd]
+        router_weights_gpu: objc.MTLBuffer,  // [n_expert, n_embd] - already on GPU
+        expert_gate_weights_gpu: [8]objc.MTLBuffer, // [n_ff, n_embd] per expert
+        expert_up_weights_gpu: [8]objc.MTLBuffer,   // [n_ff, n_embd] per expert
+        expert_down_weights_gpu: [8]objc.MTLBuffer, // [n_embd, n_ff] per expert
+        n_expert: u32,
+        n_embd: u32,
+        n_ff: u32,
+    ) ![]f32 {
+        std.debug.assert(n_expert == 8); // Mixtral
+        std.debug.assert(n_embd == 4096);
+        std.debug.assert(n_ff == 14336);
+
+        // Copy input to GPU
+        const hidden_states_ptr: [*]f32 = @ptrCast(@alignCast(objc.bufferContents(self.buf_hidden_states)));
+        @memcpy(hidden_states_ptr[0..n_embd], x);
+
+        // Create command buffer
+        const cmd_buffer = objc.commandQueueCommandBuffer(self.command_queue) orelse {
+            return error.MetalCommandBufferCreationFailed;
+        };
+        defer objc.release(cmd_buffer);
+
+        // Step 1: Router (compute logits + top-K selection)
+        try self.routerTopK(cmd_buffer, router_weights_gpu, n_expert, n_embd);
+
+        // Read back expert IDs from GPU
+        objc.commandBufferWaitUntilCompleted(cmd_buffer);
+        const expert_ids_ptr: [*]u32 = @ptrCast(@alignCast(objc.bufferContents(self.buf_expert_ids)));
+        const expert_weights_ptr: [*]f32 = @ptrCast(@alignCast(objc.bufferContents(self.buf_expert_weights)));
+        const selected_experts = [2]u32{ expert_ids_ptr[0], expert_ids_ptr[1] };
+        const selected_weights = [2]f32{ expert_weights_ptr[0], expert_weights_ptr[1] };
+
+        // Step 2: Zero output buffer
+        try self.zeroBuffer(cmd_buffer, self.buf_output, n_embd);
+
+        // Step 3: Compute selected expert outputs and accumulate
+        for (0..2) |k| {
+            const expert_idx = selected_experts[k];
+            const weight = selected_weights[k];
+
+            // Run expert FFN (fused kernel)
+            try self.expertFFNFused(
+                cmd_buffer,
+                self.buf_hidden_states,
+                expert_gate_weights_gpu[expert_idx],
+                expert_up_weights_gpu[expert_idx],
+                expert_down_weights_gpu[expert_idx],
+                self.buf_intermediate, // temporary output
+                n_embd,
+                n_ff,
+            );
+
+            // Weighted add: buf_output += weight * buf_intermediate
+            try self.weightedAdd(cmd_buffer, self.buf_output, self.buf_intermediate, weight, n_embd);
+        }
+
+        // Commit and wait
+        objc.commandBufferCommit(cmd_buffer);
+        objc.commandBufferWaitUntilCompleted(cmd_buffer);
+
+        // Copy result back to CPU
+        const result = try allocator.alloc(f32, n_embd);
+        const output_ptr: [*]f32 = @ptrCast(@alignCast(objc.bufferContents(self.buf_output)));
+        @memcpy(result, output_ptr[0..n_embd]);
+
+        return result;
+    }
