+    // =========================================================================
+    // Internal helper methods
+    // =========================================================================
+
+    fn routerTopK(
+        self: *Self,
+        cmd_buffer: objc.MTLCommandBuffer,
+        router_weights: objc.MTLBuffer,
+        n_expert: u32,
+        n_embd: u32,
+    ) !void {
+        // Compute router logits
+        const encoder1 = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+            return error.MetalEncoderCreationFailed;
+        };
+        defer objc.release(encoder1);
+
+        objc.encoderSetPipelineState(encoder1, self.pipeline_router_logits);
+        objc.encoderSetBuffer(encoder1, self.buf_hidden_states, 0, 0);
+        objc.encoderSetBuffer(encoder1, router_weights, 0, 1);
+        objc.encoderSetBuffer(encoder1, self.buf_router_logits, 0, 2);
+        objc.encoderSetBytes(encoder1, @ptrCast(&n_expert), @sizeOf(u32), 3);
+        objc.encoderSetBytes(encoder1, @ptrCast(&n_embd), @sizeOf(u32), 4);
+
+        const grid_size1 = objc.MTLSize{ .width = n_expert, .height = 1, .depth = 1 };
+        const threadgroup_size1 = objc.MTLSize{ .width = @min(n_expert, 8), .height = 1, .depth = 1 };
+        objc.encoderDispatchThreads(encoder1, grid_size1, threadgroup_size1);
+        objc.encoderEndEncoding(encoder1);
+
+        // Top-K selection
+        const encoder2 = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+            return error.MetalEncoderCreationFailed;
+        };
+        defer objc.release(encoder2);
+
+        objc.encoderSetPipelineState(encoder2, self.pipeline_router_topk);
+        objc.encoderSetBuffer(encoder2, self.buf_router_logits, 0, 0);
+        objc.encoderSetBuffer(encoder2, self.buf_expert_ids, 0, 1);
+        objc.encoderSetBuffer(encoder2, self.buf_expert_weights, 0, 2);
+        objc.encoderSetBytes(encoder2, @ptrCast(&n_expert), @sizeOf(u32), 3);
+        const k: u32 = 2;
+        objc.encoderSetBytes(encoder2, @ptrCast(&k), @sizeOf(u32), 4);
+
+        const grid_size2 = objc.MTLSize{ .width = 1, .height = 1, .depth = 1 };
+        const threadgroup_size2 = objc.MTLSize{ .width = 1, .height = 1, .depth = 1 };
+        objc.encoderDispatchThreads(encoder2, grid_size2, threadgroup_size2);
+        objc.encoderEndEncoding(encoder2);
+    }
+
