+        objc.encoderSetPipelineState(encoder2, self.pipeline_router_topk);
+        objc.encoderSetBuffer(encoder2, self.buf_router_logits, 0, 0);
+        objc.encoderSetBuffer(encoder2, self.buf_expert_ids, 0, 1);
+        objc.encoderSetBuffer(encoder2, self.buf_expert_weights, 0, 2);
+        objc.encoderSetBytes(encoder2, @ptrCast(&n_expert), @sizeOf(u32), 3);
+        const k: u32 = 2;
+        objc.encoderSetBytes(encoder2, @ptrCast(&k), @sizeOf(u32), 4);
+
+        const grid_size2 = objc.MTLSize{ .width = 1, .height = 1, .depth = 1 };
+        const threadgroup_size2 = objc.MTLSize{ .width = 1, .height = 1, .depth = 1 };
+        objc.encoderDispatchThreads(encoder2, grid_size2, threadgroup_size2);
+        objc.encoderEndEncoding(encoder2);
+    }
+
+    fn expertFFN_Q8(
+        self: *Self,
+        cmd_buffer: objc.MTLCommandBuffer,
+        input: objc.MTLBuffer,
+        gate_weights_q8: objc.MTLBuffer,
+        up_weights_q8: objc.MTLBuffer,
+        down_weights_q8: objc.MTLBuffer,
+        output: objc.MTLBuffer,
+        n_embd: u32,
+        n_ff: u32,
+    ) !void {
+        // Allocate intermediate buffer for activated values (reuse gate_buf)
+        const activated_buf = self.buf_intermediate;
+
+        // Pass 1: Compute gate/up projections + SwiGLU (parallelized)
+        // Uses SIMD-group reduction (32 threads per output neuron)
+        {
+            const encoder = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+                return error.MetalEncoderCreationFailed;
+            };
+            defer objc.release(encoder);
+
+            objc.encoderSetPipelineState(encoder, self.pipeline_expert_q8_0);
+            objc.encoderSetBuffer(encoder, input, 0, 0);
+            objc.encoderSetBuffer(encoder, gate_weights_q8, 0, 1);
+            objc.encoderSetBuffer(encoder, up_weights_q8, 0, 2);
+            objc.encoderSetBuffer(encoder, down_weights_q8, 0, 3);
+            objc.encoderSetBuffer(encoder, activated_buf, 0, 4);  // gate_buf
+            objc.encoderSetBuffer(encoder, self.buf_intermediate, 0, 5);  // up_buf (unused)
+            objc.encoderSetBuffer(encoder, output, 0, 6);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_embd), @sizeOf(u32), 7);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_ff), @sizeOf(u32), 8);
+
+            // Dispatch: n_ff threadgroups, 32 threads per group
+            const threadgroups = objc.MTLSize{ .width = n_ff, .height = 1, .depth = 1 };
+            const threads_per_group = objc.MTLSize{ .width = 32, .height = 1, .depth = 1 };
+            objc.encoderDispatchThreadgroups(encoder, threadgroups, threads_per_group);
+            objc.encoderEndEncoding(encoder);
+        }
+
+        // Pass 2: Down projection (parallelized)
+        // Computes output = down_q8 @ activated
+        {
+            const encoder = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+                return error.MetalEncoderCreationFailed;
+            };
+            defer objc.release(encoder);
+
+            objc.encoderSetPipelineState(encoder, self.pipeline_down_proj_q8_0);
+            objc.encoderSetBuffer(encoder, down_weights_q8, 0, 0);
+            objc.encoderSetBuffer(encoder, activated_buf, 0, 1);
+            objc.encoderSetBuffer(encoder, output, 0, 2);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_embd), @sizeOf(u32), 3);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_ff), @sizeOf(u32), 4);
+
+            // Dispatch: n_embd threadgroups, 32 threads per group
+            const threadgroups = objc.MTLSize{ .width = n_embd, .height = 1, .depth = 1 };
+            const threads_per_group = objc.MTLSize{ .width = 32, .height = 1, .depth = 1 };
+            objc.encoderDispatchThreadgroups(encoder, threadgroups, threads_per_group);
+            objc.encoderEndEncoding(encoder);
+        }
+    }
+
+    fn expertFFNFused(
+        self: *Self,
+        cmd_buffer: objc.MTLCommandBuffer,
+        input: objc.MTLBuffer,
+        gate_weights: objc.MTLBuffer,
+        up_weights: objc.MTLBuffer,
+        down_weights: objc.MTLBuffer,
+        output: objc.MTLBuffer,
+        n_embd: u32,
+        n_ff: u32,
+    ) !void {
+        const encoder = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+            return error.MetalEncoderCreationFailed;
+        };
+        defer objc.release(encoder);
+
+        objc.encoderSetPipelineState(encoder, self.pipeline_expert_fused);
+        objc.encoderSetBuffer(encoder, input, 0, 0);
+        objc.encoderSetBuffer(encoder, gate_weights, 0, 1);
+        objc.encoderSetBuffer(encoder, up_weights, 0, 2);
+        objc.encoderSetBuffer(encoder, down_weights, 0, 3);
+        objc.encoderSetBuffer(encoder, output, 0, 4);
+        objc.encoderSetBytes(encoder, @ptrCast(&n_embd), @sizeOf(u32), 5);
+        objc.encoderSetBytes(encoder, @ptrCast(&n_ff), @sizeOf(u32), 6);
+
