+        objc.computeEncoderSetBytes(encoder, @ptrCast(&n_embd), @sizeOf(u32), 3);
+
+        const grid_size = objc.MTLSize{ .width = n_embd, .height = 1, .depth = 1 };
+        const threadgroup_size = objc.MTLSize{ .width = @min(n_embd, 256), .height = 1, .depth = 1 };
+        objc.computeEncoderDispatchThreads(encoder, grid_size, threadgroup_size);
+        objc.computeEncoderEndEncoding(encoder);
