+
+// Helper to create compute pipeline
+fn createPipeline(
+    device: objc.MTLDevice,
+    library: objc.MTLLibrary,
+    function_name: []const u8,
+) !objc.MTLComputePipelineState {
+    const ns_name = objc.createNSString(function_name) orelse {
+        return error.StringCreationFailed;
+    };
+    defer objc.release(ns_name);
+
+    const function = objc.libraryNewFunction(library, ns_name) orelse {
+        log.err("Failed to find Metal function: {s}", .{function_name});
+        return error.MetalFunctionNotFound;
+    };
+
+    var err: ?objc.NSError = null;
+    const pipeline = objc.deviceNewComputePipelineState(device, function, &err);
+    if (pipeline == null) {
+        if (err) |e| {
+            const desc = objc.errorGetDescription(e);
+            log.err("Failed to create pipeline for {s}: {s}", .{ function_name, desc });
+        }
+        return error.MetalPipelineCreationFailed;
+    }
+
+    return pipeline.?;
+}

